/* --- MIRON INSIGHT FLOATING POPOVER --- */
.miron-popover {
    position: absolute;
    z-index: 2300;
    width: 320px;
    max-height: 420px;
    background: rgba(20, 20, 20, 0.9);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    border: 1px solid rgba(66, 215, 184, 0.25);
    border-radius: 24px;
    box-shadow: 0 20px 50px rgba(0,0,0,0.6), 0 0 20px rgba(66, 215, 184, 0.1);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    animation: popoverReveal 0.4s cubic-bezier(0.16, 1, 0.3, 1);
    transform-origin: top center;
}

@keyframes popoverReveal {
    from { opacity: 0; transform: translateY(10px) scale(0.95); }
    to { opacity: 1; transform: translateY(0) scale(1); }
}

.pop-header {
    padding: 12px 16px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    border-bottom: 1px solid rgba(255,255,255,0.05);
    background: rgba(255,255,255,0.02);
}

.miron-status {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.7rem;
    font-weight: 700;
    letter-spacing: 1px;
    color: var(--accent-teal);
    text-transform: uppercase;
}

.status-orb {
    width: 6px; height: 6px;
    background: var(--accent-teal);
    border-radius: 50%;
    box-shadow: 0 0 8px var(--accent-teal);
    animation: statusPulse 2s infinite;
}

@keyframes statusPulse {
    0%, 100% { opacity: 1; transform: scale(1); }
    50% { opacity: 0.5; transform: scale(1.3); }
}

.pop-content {
    flex: 1;
    padding: 14px;
    overflow-y: auto;
    display: flex;
    flex-direction: column;
    gap: 12px;
    scrollbar-width: none;
}
.pop-content::-webkit-scrollbar { display: none; }

.insight-msg {
    max-width: 90%;
    font-size: 0.85rem;
    line-height: 1.5;
}

.insight-miron {
    align-self: flex-start;
}

.insight-user {
    align-self: flex-end;
}

.thought-trace-mini {
    font-family: 'Newsreader', serif;
    font-style: italic;
    color: #888;
    font-size: 0.75rem;
    margin-bottom: 3px;
    display: block;
}

.bubble-mini {
    padding: 10px 14px;
    border-radius: 16px;
}

.miron-bubble-mini {
    background: rgba(255,255,255,0.04);
    border: 1px solid rgba(255,255,255,0.06);
    color: #e0e0e0;
    border-top-left-radius: 4px;
}

.user-bubble-mini {
    background: linear-gradient(135deg, #1a1a1a, #0a0a0a);
    border: 1px solid rgba(66, 215, 184, 0.2);
    color: var(--accent-teal);
    border-top-right-radius: 4px;
}

.pop-footer {
    padding: 10px;
    background: rgba(0,0,0,0.2);
    border-top: 1px solid rgba(255,255,255,0.05);
}

.insight-dock {
    background: rgba(255,255,255,0.05);
    border-radius: 14px;
    padding: 2px;
    display: flex;
    align-items: center;
    border: 1px solid rgba(255,255,255,0.08);
}

.insight-dock input {
    flex: 1;
    background: transparent;
    border: none;
    outline: none;
    color: white;
    padding: 6px 10px;
    font-family: 'Poppins', sans-serif;
    font-size: 0.8rem;
}

.insight-send-btn {
    width: 28px; height: 28px;
    border-radius: 8px;
    border: none;
    background: var(--accent-teal);
    color: #0c0c0c;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
}

/* --- CONTEXT MENU --- */

const [contextMenu, setContextMenu] = useState(null); // { x, y, text }
const [mironInsight, setMironInsight] = useState(null); // { x, y, text, conversation: [] }
const [insightInput, setInsightInput] = useState('');
const [isInsightTyping, setIsInsightTyping] = useState(false);

