const handlePopoverDragStart = (e) => {
    if (!mironInsight) return;
    const clientX = e.clientX || (e.touches && e.touches[0].clientX);
    const clientY = e.clientY || (e.touches && e.touches[0].clientY);

    dragOffset.current = {
        x: clientX - mironInsight.x,
        y: clientY - mironInsight.y
    };
    setIsDraggingPopover(true);
};

useEffect(() => {
    const handleMove = (e) => {
        if (!isDraggingPopover || !mironInsight) return;

        const clientX = e.clientX || (e.touches && e.touches[0].clientX);
        const clientY = e.clientY || (e.touches && e.touches[0].clientY);

        let newX = clientX - dragOffset.current.x;
        let newY = clientY - dragOffset.current.y;

        // Boundary Clamping (320px width, ~420px height)
        newX = Math.max(0, Math.min(newX, window.innerWidth - 320));
        newY = Math.max(0, Math.min(newY, window.innerHeight - 150)); // Allow footer to stick out slightly if needed

        setMironInsight(prev => ({ ...prev, x: newX, y: newY }));
    };

    const handleEnd = () => setIsDraggingPopover(false);

    if (isDraggingPopover) {
        window.addEventListener('mousemove', handleMove);
        window.addEventListener('mouseup', handleEnd);
        window.addEventListener('touchmove', handleMove, { passive: false });
        window.addEventListener('touchend', handleEnd);
    }

    return () => {
        window.removeEventListener('mousemove', handleMove);
        window.removeEventListener('mouseup', handleEnd);
        window.removeEventListener('touchmove', handleMove);
        window.removeEventListener('touchend', handleEnd);
    };
}, [isDraggingPopover, mironInsight]);

