 423 |                     // 1. BACKWARD SCAN (Find start)
 424 |                     let currentStartNode = startNode;
 425 |                     let currentStartOffset = startOffset;
 426 |                     let finalStartNode = startNode;
 427 |                     let finalStartOffset = 0;
 428 | 
 429 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 430 |                     let lastPuncIndex = -1;
 431 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 432 |                         if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 433 |                     }
 434 | 
 435 |                     if (lastPuncIndex !== -1) {
 436 |                         finalStartOffset = lastPuncIndex + 1;
 437 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 438 |                     } else {
 439 |                         const walker = createWalker(pageBoundary);
 440 |                         walker.currentNode = currentStartNode;
 441 |                         let prevNode = walker.previousNode();
 442 |                         let foundStart = false;
 443 | 
 444 |                         while (prevNode && !foundStart) {
 445 |                             const text = prevNode.textContent;
 446 |                             for (let i = text.length - 1; i >= 0; i--) {
 447 |                                 if (sentenceEndRegex.test(text[i])) {
 448 |                                     finalStartNode = prevNode; finalStartOffset = i + 1;
 449 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 450 |                                     foundStart = true; break;
 451 |                                 }
 452 |                             }
 453 |                             if (!foundStart) {
 454 |                                 finalStartNode = prevNode; finalStartOffset = 0;
 455 |                                 prevNode = walker.previousNode();
 456 |                             }
 457 |                         }
 458 |                     }
 459 | 
 460 |                     // 2. FORWARD SCAN (Find end)
 461 |                     let currentEndNode = startNode;
 462 |                     let currentEndOffset = startOffset;
 463 |                     let finalEndNode = startNode;
 464 |                     let finalEndOffset = startNode.textContent.length;
 465 | 
 466 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 467 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
